package org.eclipse.rdf4j.http.server.repository;

import static org.assertj.core.api.Assertions.assertThat;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import java.util.HashMap;
import java.util.Map;

import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.explanation.Explanation;
import org.junit.jupiter.api.Test;
import org.springframework.mock.web.MockHttpServletRequest;
import org.springframework.mock.web.MockHttpServletResponse;

class ExplainQueryResultViewTest {

	@Test
	void shouldReturnTupleExprEnvelopeWhenRequested() throws Exception {
		ExplainQueryResultView view = new ExplainQueryResultView();
		Explanation explanation = mock(Explanation.class);
		StatementPattern tupleExpr = new StatementPattern(new Var("s"), new Var("p"), new Var("o"));
		Map<String, Object> model = new HashMap<>();
		MockHttpServletRequest request = new MockHttpServletRequest();
		MockHttpServletResponse response = new MockHttpServletResponse();

		model.put(QueryResultView.QUERY_EXPLAIN_RESULT_KEY, explanation);
		request.setParameter("Accept", "application/json");
		request.setParameter("explain-tuple-expr", "true");
		when(explanation.toJson()).thenReturn("{\"type\":\"Projection\"}");
		when(explanation.tupleExpr()).thenReturn(tupleExpr);

		view.render(model, request, response);

		assertThat(response.getStatus()).isEqualTo(MockHttpServletResponse.SC_OK);
		assertThat(response.getContentAsString())
				.contains("\"plan\"")
				.contains("\"type\":\"Projection\"")
				.contains("\"tupleExprJson\"");
	}

	@Test
	void shouldKeepLegacyPlanJsonWhenEnvelopeIsNotRequested() throws Exception {
		ExplainQueryResultView view = new ExplainQueryResultView();
		Explanation explanation = mock(Explanation.class);
		Map<String, Object> model = new HashMap<>();
		MockHttpServletRequest request = new MockHttpServletRequest();
		MockHttpServletResponse response = new MockHttpServletResponse();

		model.put(QueryResultView.QUERY_EXPLAIN_RESULT_KEY, explanation);
		request.setParameter("Accept", "application/json");
		when(explanation.toJson()).thenReturn("{\"type\":\"Projection\"}");

		view.render(model, request, response);

		assertThat(response.getStatus()).isEqualTo(MockHttpServletResponse.SC_OK);
		assertThat(response.getContentAsString()).isEqualTo("{\"type\":\"Projection\"}");
	}
}
